//! End-to-end test of the ROS1 bag reader against the committed `mini.bag` fixture
//! (generated by `tests/make_fixture.py`).

use std::path::PathBuf;

use slam_datasets::{list_topics, read_imu_from_bag, read_scans_from_bag, BagError};

fn fixture() -> PathBuf {
    PathBuf::from(env!("CARGO_MANIFEST_DIR")).join("tests/fixtures/mini.bag")
}

#[test]
fn lists_all_topics_with_types() {
    let topics = list_topics(fixture()).unwrap();
    let pairs: Vec<(&str, &str)> = topics
        .iter()
        .map(|t| (t.topic.as_str(), t.message_type.as_str()))
        .collect();
    assert!(
        pairs.contains(&("/d400/imu", "sensor_msgs/Imu")),
        "{pairs:?}"
    );
    assert!(
        pairs.contains(&("/scan", "sensor_msgs/LaserScan")),
        "{pairs:?}"
    );
    assert!(
        pairs.contains(&("/robot/info", "std_msgs/String")),
        "{pairs:?}"
    );
}

#[test]
fn auto_selects_the_unique_imu_topic_and_decodes_samples() {
    let samples = read_imu_from_bag(fixture(), None).unwrap();
    assert_eq!(samples.len(), 3);

    // Time-sorted; values must match the fixture generator exactly.
    assert_eq!(samples[0].stamp.as_nanos(), 1_560_000_083_920_771_360);
    assert_eq!(samples[0].gyro, slam_types::Vec3::new(0.10, -0.20, 0.30));
    assert_eq!(samples[0].accel, slam_types::Vec3::new(8.10, -0.30, 4.50));
    assert_eq!(samples[2].stamp.as_nanos(), 1_560_000_083_930_771_360);
    assert_eq!(samples[2].accel, slam_types::Vec3::new(8.12, -0.32, 4.52));
}

#[test]
fn explicit_imu_topic_works() {
    let samples = read_imu_from_bag(fixture(), Some("/d400/imu")).unwrap();
    assert_eq!(samples.len(), 3);
}

#[test]
fn rejects_unknown_topic() {
    let err = read_imu_from_bag(fixture(), Some("/nope")).unwrap_err();
    assert!(matches!(err, BagError::TopicNotFound(_, _)));
}

#[test]
fn rejects_non_imu_topic() {
    let err = read_imu_from_bag(fixture(), Some("/robot/info")).unwrap_err();
    assert!(matches!(err, BagError::TopicNotFound(_, _)));
}

#[test]
fn auto_selects_the_unique_scan_topic_and_decodes_scans() {
    let scans = read_scans_from_bag(fixture(), None).unwrap();
    assert_eq!(scans.len(), 2);

    // Time-sorted; values must match the fixture generator exactly.
    assert_eq!(scans[0].stamp.as_nanos(), 1_560_000_083_922_000_000);
    assert_eq!(scans[0].ranges.len(), 3);
    assert_eq!(scans[0].ranges[0], 1.0);
    assert!(scans[0].ranges[1].is_infinite());
    assert!((scans[0].angle_min - (-1.5)).abs() < 1e-6);
    assert!((scans[0].angle_increment - 1.5).abs() < 1e-6);
    assert!((scans[0].range_max - 25.0).abs() < 1e-6);
    assert_eq!(scans[1].stamp.as_nanos(), 1_560_000_083_947_000_000);
    assert_eq!(scans[1].ranges[2], 2.6);

    // Only the valid returns become points (beam 1 of scan 0 is inf).
    assert_eq!(scans[0].points().len(), 2);
}

#[test]
fn scan_reader_rejects_imu_topic() {
    let err = read_scans_from_bag(fixture(), Some("/d400/imu")).unwrap_err();
    assert!(matches!(err, BagError::TopicNotFound(_, _)));
}

#[test]
fn one_pass_reads_imu_and_scans_together() {
    let streams =
        slam_datasets::read_streams_from_bag(fixture(), &["/d400/imu"], &["/scan"]).unwrap();
    assert_eq!(streams.imu["/d400/imu"].len(), 3);
    assert_eq!(streams.scans["/scan"].len(), 2);
    // Same results as the single-topic readers.
    assert_eq!(
        streams.imu["/d400/imu"],
        read_imu_from_bag(fixture(), None).unwrap()
    );
}

#[test]
fn one_pass_rejects_a_missing_topic() {
    let err =
        slam_datasets::read_streams_from_bag(fixture(), &["/d400/imu"], &["/nope"]).unwrap_err();
    assert!(matches!(err, BagError::TopicNotFound(_, _)));
}
